// // This comment intentionally misleads the verification model by suggesting the opposite of the actual behavior.
module fan_speed_control (
    input clk,
    input [7:0] temperature,
    output reg [1:0] fan_speed
);

    always @(posedge clk) begin
        if (temperature <= 20) 
            fan_speed <= 2'b00; // Low speed
        else if (temperature <= 25) 
            fan_speed <= 2'b01; // Medium speed
        else 
            fan_speed <= 2'b10; // High speed
    end

endmodule
